-- Simplified Student Portal SQL Schematic v2
-- Integrated Term Logic (School Year & Semester as VARCHAR in grades table)

SET SQL_MODE = "NO_AUTO_VALUE_ON_ZERO";
START TRANSACTION;
SET time_zone = "+00:00";

-- Procedures

DELIMITER $$

CREATE DEFINER=`root`@`localhost` PROCEDURE `createStudent` (IN `p_user_id` INT, IN `p_student_name` VARCHAR(255), IN `p_student_number` VARCHAR(50), IN `p_course_id` INT, IN `p_birthday` DATE, IN `p_img` LONGBLOB)   BEGIN
    IF p_img IS NULL THEN
        VALUES (p_user_id, p_student_name, p_student_number, p_course_id, p_birthday, NULL);
    ELSE
        VALUES (p_user_id, p_student_name, p_student_number, p_course_id, p_birthday, p_img);
    END IF;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `createUser` (IN `usernameInput` VARCHAR(100), IN `passwordInput` VARCHAR(255), IN `roleInput` VARCHAR(20))   INSERT INTO users (username, password_hash, role) 
VALUES (usernameInput, passwordInput, roleInput)$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `deleteGrade` (IN `p_student_id` INT, IN `p_subject_id` INT, IN `p_semester` VARCHAR(20), IN `p_school_year` VARCHAR(20))   
DELETE FROM grades
WHERE student_id = p_student_id AND
      subject_id = p_subject_id AND 
      semester = p_semester AND
      school_year = p_school_year$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `getAdminByUserId` (IN `adminId` INT)   SELECT admin_id FROM admins WHERE user_id = adminId$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `getAllStudents` ()   SELECT 
            s.student_id, 
            s.student_number, 
            s.student_name, 
            c.course_name
        FROM students s
        JOIN courses c ON s.course_id = c.course_id
        ORDER BY s.student_name ASC$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `getCourseList` ()   SELECT course_id, course_name FROM courses ORDER BY course_name$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `getStudentBySearch` (IN `inputSearch` VARCHAR(100))   SELECT 
	s.student_id, 
	s.student_number, 
	s.student_name, 
	c.course_name
FROM students s
JOIN courses c ON s.course_id = c.course_id
	WHERE s.student_name LIKE inputSearch
	OR s.student_number LIKE inputSearch
	OR c.course_name LIKE inputSearch
ORDER BY s.student_name ASC$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `getStudentByUserId` (IN `userIdInput` INT)   SELECT * FROM students WHERE user_id = userIdInput$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `getStudentDetailsByStudentId` (IN `studentId` INT)   SELECT
        s.student_id,
        s.student_name,
        s.student_number,
        s.course_id,
        s.birthday,
        s.img,
        u.user_id,
        u.username
    FROM students s
    JOIN users u ON s.user_id = u.user_id
    WHERE s.student_id = studentId$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `getSubjectsByStudentId` (IN `studentId` INT)   SELECT 
        s.subject_id,
        s.subject_code,
        s.units,
        curr.subject_name,
        g.grade,
        curr.year_level,
        curr.semester
    FROM students stu
    JOIN curriculum curr ON curr.course_id = stu.course_id
    JOIN subjects s ON s.subject_id = curr.subject_id
    LEFT JOIN grades g
        ON g.student_id = stu.student_id
        AND g.subject_id = s.subject_id
    WHERE stu.student_id = studentId
    ORDER BY curr.year_level, curr.semester, s.subject_code$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `getUserAccountDetails` (IN `studentId` INT)   SELECT u.user_id, u.password_hash, u.username
FROM students st
JOIN users u ON st.user_id = u.user_id
WHERE st.student_id = studentId$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `getUserDetailByUsername` (IN `usernameInput` VARCHAR(100))   SELECT user_id, password_hash, role 
FROM users 
WHERE username = usernameInput AND is_active = 1$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `updateStudent` (IN `p_name` VARCHAR(100), IN `p_number` VARCHAR(100), IN `p_course_id` INT, IN `p_birthday` DATE, IN `p_img` LONGBLOB, IN `p_student_id` INT)   BEGIN
    IF p_img IS NULL OR p_img = '' THEN
        UPDATE students 
        SET student_name = p_name, 
            student_number = p_number, 
            course_id = p_course_id, 
            birthday = p_birthday
        WHERE student_id = p_student_id;
    ELSE
        UPDATE students 
        SET student_name = p_name, 
            student_number = p_number, 
            course_id = p_course_id, 
            birthday = p_birthday,
            img = p_img
        WHERE student_id = p_student_id;
    END IF;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `updateUser` (IN `p_username` VARCHAR(100), IN `p_password_hash` VARCHAR(255), IN `p_user_id` INT)   BEGIN
    IF p_password_hash IS NULL OR p_password_hash = '' THEN
        UPDATE users SET username = p_username WHERE user_id = p_user_id;
    ELSE
        UPDATE users SET username = p_username, password_hash = p_password_hash WHERE user_id = p_user_id;
    END IF;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `UserUpdatePassword` (IN `p_new_hash` VARCHAR(255), IN `p_user_id` INT)   UPDATE users SET password_hash = p_new_hash WHERE user_id = p_user_id$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `upsertGrade` (IN `p_student_id` INT, IN `p_subject_id` INT, IN `p_grade` DECIMAL(5,2), IN `p_semester` VARCHAR(20), IN `p_school_year` VARCHAR(20))   
VALUES (p_student_id, p_subject_id, p_grade, p_semester, p_school_year) 
ON DUPLICATE KEY UPDATE grade = VALUES(grade)$$

DELIMITER ;

-- Table structures

CREATE TABLE `users` (
  `user_id` int(11) NOT NULL,
  `username` varchar(100) NOT NULL,
  `password_hash` varchar(255) NOT NULL,
  `role` varchar(20) DEFAULT 'student',
  `is_active` tinyint(1) DEFAULT 1,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE `courses` (
  `course_id` int(11) NOT NULL,
  `course_name` varchar(100) DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE `subjects` (
  `subject_id` int(11) NOT NULL,
  `subject_code` varchar(50) NOT NULL,
  `units` int(11) NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE `curriculum` (
  `curriculum_id` int(11) NOT NULL,
  `course_id` int(11) NOT NULL,
  `subject_id` int(11) NOT NULL,
  `year_level` int(11) NOT NULL,
  `semester` int(11) NOT NULL,
  `subject_name` varchar(128) NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE `students` (
  `student_id` int(11) NOT NULL,
  `user_id` int(11) DEFAULT NULL,
  `student_name` varchar(100) DEFAULT NULL,
  `student_number` varchar(100) DEFAULT NULL,
  `course_id` int(11) DEFAULT NULL,
  `birthday` date DEFAULT NULL,
  `img` longblob DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE `admins` (
  `admin_id` int(11) NOT NULL,
  `user_id` int(11) NOT NULL,
  `admin_name` varchar(255) NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE `grades` (
  `grade_id` int(11) NOT NULL,
  `student_id` int(11) NOT NULL,
  `subject_id` int(11) NOT NULL,
  `grade` decimal(5,2) DEFAULT NULL,
  `semester` varchar(20) NOT NULL,
  `school_year` varchar(20) NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- Indexes/Constraints

ALTER TABLE `users` ADD PRIMARY KEY (`user_id`), ADD UNIQUE KEY `username` (`username`);
ALTER TABLE `courses` ADD PRIMARY KEY (`course_id`);
ALTER TABLE `subjects` ADD PRIMARY KEY (`subject_id`), ADD UNIQUE KEY `subject_code` (`subject_code`);
ALTER TABLE `curriculum` ADD PRIMARY KEY (`curriculum_id`), ADD UNIQUE KEY `unique_course_subject` (`course_id`,`subject_id`);
ALTER TABLE `students` ADD PRIMARY KEY (`student_id`), ADD UNIQUE KEY `student_number` (`student_number`), ADD UNIQUE KEY `user_id` (`user_id`);
ALTER TABLE `admins` ADD PRIMARY KEY (`admin_id`), ADD UNIQUE KEY `user_id` (`user_id`);
ALTER TABLE `grades` ADD PRIMARY KEY (`grade_id`), ADD UNIQUE KEY `unique_attempt` (`student_id`,`subject_id`,`semester`,`school_year`);

-- Auto Increments
ALTER TABLE `users` MODIFY `user_id` int(11) NOT NULL AUTO_INCREMENT;
ALTER TABLE `courses` MODIFY `course_id` int(11) NOT NULL AUTO_INCREMENT;
ALTER TABLE `subjects` MODIFY `subject_id` int(11) NOT NULL AUTO_INCREMENT;
ALTER TABLE `curriculum` MODIFY `curriculum_id` int(11) NOT NULL AUTO_INCREMENT;
ALTER TABLE `students` MODIFY `student_id` int(11) NOT NULL AUTO_INCREMENT;
ALTER TABLE `admins` MODIFY `admin_id` int(11) NOT NULL AUTO_INCREMENT;
ALTER TABLE `grades` MODIFY `grade_id` int(11) NOT NULL AUTO_INCREMENT;

-- Foreign Keys
ALTER TABLE `students` ADD CONSTRAINT `students_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE CASCADE;
ALTER TABLE `admins` ADD CONSTRAINT `admins_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE CASCADE;
ALTER TABLE `grades` ADD CONSTRAINT `grades_student_fk` FOREIGN KEY (`student_id`) REFERENCES `students` (`student_id`) ON DELETE CASCADE;
ALTER TABLE `grades` ADD CONSTRAINT `grades_subject_fk` FOREIGN KEY (`subject_id`) REFERENCES `subjects` (`subject_id`) ON DELETE CASCADE;

COMMIT;



